import React, { useEffect, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import Footer from './Footer'; // ✅ ADDED

function useReveal() {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const obs = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        setVisible(true);
        obs.disconnect();
      }
    }, { threshold: 0.15 });

    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  return [ref, visible];
}

function Reveal({ children, delay = 0 }) {
  const [ref, visible] = useReveal();

  return (
    <div
      ref={ref}
      style={{
        opacity: visible ? 1 : 0,
        transform: visible ? 'translateY(0)' : 'translateY(30px)',
        transition: `all 0.7s cubic-bezier(.22,1,.36,1) ${delay}s`,
      }}
    >
      {children}
    </div>
  );
}

export default function About() {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 30);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <div style={{ background: 'var(--bg-base)', color: 'var(--text-primary)' }}>

      <nav style={{
        position: 'fixed',
        top: 0,
        width: '100%',
        height: 70,
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '0 40px',
        backdropFilter: 'blur(18px)',
        background: scrolled ? 'rgba(10,12,22,0.85)' : 'rgba(10,12,22,0.5)',
        borderBottom: scrolled ? '1px solid rgba(255,255,255,0.05)' : 'transparent',
      }}>
        <Link to="/">StudentBridge</Link>
        <div style={{ display: 'flex', gap: 20 }}>
          <Link to="/contact">Contact</Link>
          <Link to="/login">Sign In</Link>
        </div>
      </nav>

      <section style={{ paddingTop: 140, textAlign: 'center' }}>
        <Reveal>
          <h1>About StudentBridge</h1>
        </Reveal>

        <Reveal delay={0.2}>
          <p style={{ maxWidth: 700, margin: '20px auto', color: 'var(--text-secondary)' }}>
            StudentBridge is an AI-powered career platform that connects students with companies through intelligent job matching, learning tools, and career guidance.
          </p>
        </Reveal>
      </section>

      <section style={{ padding: 60 }}>
        <div style={{ maxWidth: 900, margin: '0 auto', lineHeight: 1.7 }}>
          <h3>Problem</h3>
          <p>Students struggle to find relevant jobs and lack career direction.</p>

          <h3>Solution</h3>
          <p>We provide AI-driven matching, skill development, and mentorship in one platform.</p>

          <h3>Technology</h3>
          <p>React.js, Node.js, MySQL, Socket.io, GROQ AI</p>
        </div>
      </section>

      <Footer />
    </div>
  );
}
